request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?originalId ?normalizedId ?created ?choreoName WHERE {
  ?org a bboExt:Organization .
  ?org tai:organizationId "67e70970f0404a7e87122700ad26d87b" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:originalId ?originalId ;
         tai:normalizedId ?normalizedId ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
  OPTIONAL { ?model tai:belongsTo ?org . }

  ?definitions tai:belongsTo ?model .
  OPTIONAL { ?definitions bboExt:isClosed ?closed . }

  ?choreo tai:belongsTo ?definitions .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  ?task bbo:name ?taskName .
  FILTER(
    CONTAINS(LCASE(STR(?taskName)), "bike") ||
    CONTAINS(LCASE(STR(?taskName)), "rental") ||
    CONTAINS(LCASE(STR(?taskName)), "insurance")
  )
}
ORDER BY DESC(?created)
LIMIT 25

